"use client";
import { useState, useEffect, use } from 'react';
import { piece } from '../types/Piece';

type PieceProps = piece & {
    chessboard: (piece | null)[][];
}

export default function Piece({ position, image, posibleMoves, chessboard }: PieceProps) {
    const [isSelected, setIsSelected] = useState(false);
    const handleClick = () => {
        setIsSelected(!isSelected);
        showPossibleMoves(position, posibleMoves, chessboard);
    };


    return (
        <div className={`piece w-24 h-24 ${isSelected ? `selected` : ''}`}
             style={{ backgroundImage: `url(${image})`,
             backgroundRepeat: 'no-repeat', backgroundPosition: `50% 50%`,
             backgroundSize: '100% 100%'}} onClick={handleClick}>

        </div>
    );
}

function showPossibleMoves(position: { row: number; col: number }, posibleMoves: { dx: number; dy: number; repeat: boolean }[], chessboard: (piece | null)[][]) {
    posibleMoves.forEach(move => {
        console.log(`Move: dx=${move.dx}, dy=${move.dy}, repeat=${move.repeat}`);
        chessboard[position.row + move.dy][position.col + move.dx]
    });
    

}